"""Stage 1: Document ingestion — reads raw documents into structured records."""

import hashlib
from datetime import datetime


class Ingester:
    """Reads raw document dicts and produces ingestion records."""

    REQUIRED_KEYS = {"title", "body", "source"}

    def __init__(self, strict=True):
        self.strict = strict
        self._ingested = []

    def ingest(self, raw_documents):
        """Ingest a list of raw document dicts.

        Each document must contain 'title', 'body', and 'source'.
        Returns a list of ingestion records with metadata attached.
        """
        results = []
        for doc in raw_documents:
            missing = self.REQUIRED_KEYS - set(doc.keys())
            if missing:
                if self.strict:
                    raise ValueError(f"Missing keys: {missing}")
                continue
            record = {
                "id": self._make_id(doc),
                "title": doc["title"].strip(),
                "body": doc["body"].strip(),
                "source": doc["source"],
                "ingested_at": datetime.utcnow().isoformat(),
                "word_count": len(doc["body"].split()),
                "stage": "ingested",
            }
            results.append(record)
        self._ingested.extend(results)
        return results

    def get_stats(self):
        """Return ingestion statistics."""
        total = len(self._ingested)
        avg_words = (
            sum(r["word_count"] for r in self._ingested) / total if total else 0
        )
        return {"total_ingested": total, "avg_word_count": round(avg_words, 1)}

    def _make_id(self, doc):
        content = f"{doc['title']}:{doc['source']}"
        return hashlib.sha256(content.encode()).hexdigest()[:12]

