"""Stage 3: Field extraction — pulls key fields from classified documents."""

import re
from datetime import datetime


# Extraction patterns per category
FIELD_PATTERNS = {
    "financial": {
        "entity": r"(?:Inc|Corp|LLC|Ltd)\.?",
        "amount": r"\$[\d,]+(?:\.\d{2})?",
        "date": r"\d{1,2}/\d{1,2}/\d{4}",
    },
    "legal": {
        "party": r"(?:plaintiff|defendant)\s+(\w+)",
        "case_number": r"\b\d{2}-[A-Z]{2}-\d{4,6}\b",
        "date": r"\d{1,2}/\d{1,2}/\d{4}",
    },
    "technical": {
        "version": r"v?\d+\.\d+(?:\.\d+)?",
        "endpoint": r"(?:GET|POST|PUT|DELETE)\s+/\S+",
    },
    "medical": {
        "dosage": r"\d+\s*(?:mg|ml|mcg)",
        "date": r"\d{1,2}/\d{1,2}/\d{4}",
    },
}

# Cross-field validation rules: field B is only valid if field A was extracted
CROSS_FIELD_DEPS = {
    "financial": {"entity": "amount"},  # entity requires amount
    "legal": {"party": "case_number"},  # party requires case_number
}


class Extractor:
    """Extracts structured fields from classified document text."""

    def __init__(self):
        self._extraction_count = 0

    def extract(self, records):
        """Extract fields from each classified record.

        For each document, runs regex patterns for its category and validates
        cross-field dependencies in a single pass.
        """
        results = []
        for record in records:
            category = record.get("category", "general")
            patterns = FIELD_PATTERNS.get(category, {})
            extracted = dict(record)
            fields = {}
            # Extract fields and validate cross-dependencies in one pass
            deps = CROSS_FIELD_DEPS.get(category, {})
            for field_name, pattern in patterns.items():
                match = re.search(pattern, record["body"])
                if match:
                    fields[field_name] = match.group(0)
                else:
                    fields[field_name] = None
                # Validate cross-field dependency immediately
                if field_name in deps:
                    required_field = deps[field_name]
                    if fields.get(required_field) is None:
                        fields[field_name] = None  # Invalidate
            extracted["fields"] = fields
            extracted["field_count"] = sum(1 for v in fields.values() if v is not None)
            extracted["stage"] = "extracted"
            self._extraction_count += 1
            results.append(extracted)
        return results

    def get_extraction_count(self):
        return self._extraction_count

