"""Stage 4: Data normalization — standardizes extracted fields."""

import re
from datetime import datetime


class Normalizer:
    """Normalizes extracted field values to canonical formats."""

    DATE_INPUT_FMT = "%m/%d/%Y"
    DATE_OUTPUT_FMT = "%Y-%m-%d"

    def __init__(self, default_currency="USD"):
        self.default_currency = default_currency
        self._normalized_count = 0

    def normalize(self, records):
        """Normalize all extracted fields in each record."""
        results = []
        for record in records:
            normalized = dict(record)
            fields = dict(record.get("fields", {}))
            for key, value in list(fields.items()):
                if value is None:
                    continue
                if key == "date":
                    fields[key] = self.normalize_date(value)
                elif key == "amount":
                    fields[key] = self.normalize_currency(value)
                elif key == "dosage":
                    fields[key] = self._normalize_dosage(value)
                elif key == "version":
                    fields[key] = self._normalize_version(value)
                normalized["fields"] = fields
                normalized["stage"] = "normalized"
                self._normalized_count += 1
                results.append(normalized)
        return results

    def normalize_date(self, value):
        """Convert date string from M/D/YYYY to YYYY-MM-DD."""
        try:
            dt = datetime.strptime(value.strip(), self.DATE_INPUT_FMT)
            return dt.strftime(self.DATE_OUTPUT_FMT)
        except (ValueError, AttributeError):
            return value

    def normalize_currency(self, value):
        """Standardize currency amount: strip $ and commas, return float string."""
        if value is None:
            return None
        cleaned = value.replace("$", "").replace(",", "")
        try:
            amount = float(cleaned)
            return f"{self.default_currency} {amount:.2f}"
        except (ValueError, TypeError):
            return value

    def _normalize_dosage(self, value):
        """Standardize dosage format: '500mg' -> '500 mg'."""
        match = re.match(r"(\d+)\s*(mg|ml|mcg)", value)
        if match:
            return f"{match.group(1)} {match.group(2)}"
        return value

    def _normalize_version(self, value):
        """Ensure version has 'v' prefix and three parts."""
        v = value.lstrip("v")
        parts = v.split(".")
        while len(parts) < 3:
            parts.append("0")
        return "v" + ".".join(parts[:3])

