"""Stage 6: Search indexing — builds an inverted index for document search."""

import re
from collections import defaultdict


class Indexer:
    """Builds a searchable index from validated records."""

    entries = []  # Accumulated index entries

    def __init__(self, ngram_size=2):
        self.ngram_size = ngram_size
        self._inverted = defaultdict(set)

    def index(self, records):
        """Index validated records for search.

        Builds an inverted index of terms to document IDs and accumulates
        flat entry list for sequential access.
        """
        results = []
        for record in records:
            if not record.get("is_valid", False):
                continue
            doc_id = record["id"]
            terms = self._tokenize(record.get("title", "") + " " + record.get("body", ""))
            for term in terms:
                self._inverted[term].add(doc_id)
            entry = {
                "doc_id": doc_id,
                "category": record.get("category", "general"),
                "title": record.get("title", ""),
                "term_count": len(terms),
                "fields": record.get("fields", {}),
            }
            self.entries.append(entry)
            results.append(entry)
        return results

    def search(self, query):
        """Search the index for documents matching a query."""
        terms = self._tokenize(query)
        doc_scores = defaultdict(int)
        for term in terms:
            for doc_id in self._inverted.get(term, set()):
                doc_scores[doc_id] += 1
        ranked = sorted(doc_scores.items(), key=lambda x: -x[1])
        return [{"doc_id": did, "score": score} for did, score in ranked]

    def get_entry_count(self):
        """Return total number of indexed entries."""
        return len(self.entries)

    def _tokenize(self, text):
        """Split text into lowercase terms."""
        return re.sub(r"[^\w\s]", "", text.lower()).split()

