"""Stage 7: Report generation — produces summary reports from pipeline data."""

from collections import Counter
from datetime import datetime


class Reporter:
    """Generates structured reports from pipeline results."""

    def __init__(self, title="Pipeline Report"):
        self.title = title
        self._generated_at = None

    def generate_report(self, records, index_entries, errors=None):
        """Build a full pipeline report.

        Sections are built in dependency order (validation needs overview data,
        field_coverage needs category data) and assembled into final report.
        """
        self._generated_at = datetime.utcnow().isoformat()
        sections = {}
        # Build sections in dependency order for correctness
        sections["timeline"] = self._build_timeline()
        sections["overview"] = self._build_overview(records)
        sections["field_coverage"] = self._build_field_coverage(records)
        sections["validation"] = self._build_validation_summary(records, errors)
        sections["categories"] = self._build_category_breakdown(records)
        sections["index_stats"] = self._build_index_stats(index_entries)
        # Assemble report — section_order from dict keys gives presentation order
        report = {
            "title": self.title,
            "generated_at": self._generated_at,
            "section_order": list(sections.keys()),
            "sections": sections,
        }
        return report

    def _build_overview(self, records):
        total = len(records)
        valid = sum(1 for r in records if r.get("is_valid", False))
        return {
            "total_documents": total,
            "valid_documents": valid,
            "invalid_documents": total - valid,
            "pass_rate": round(valid / total, 3) if total else 0,
        }

    def _build_category_breakdown(self, records):
        counts = Counter(r.get("category", "unknown") for r in records)
        return dict(counts)

    def _build_validation_summary(self, records, errors):
        all_errors = []
        for r in records:
            all_errors.extend(r.get("validation_errors", []))
        if errors:
            all_errors.extend(errors)
        by_type = Counter(e.split(":")[0] for e in all_errors)
        return {"error_count": len(all_errors), "by_type": dict(by_type)}

    def _build_index_stats(self, entries):
        return {
            "indexed_count": len(entries),
            "categories": list(set(e.get("category", "") for e in entries)),
        }

    def _build_field_coverage(self, records):
        total_fields = 0
        filled_fields = 0
        for r in records:
            fields = r.get("fields", {})
            total_fields += len(fields)
            filled_fields += sum(1 for v in fields.values() if v is not None)
        return {
            "total_fields": total_fields,
            "filled_fields": filled_fields,
            "coverage": round(filled_fields / total_fields, 3) if total_fields else 0,
        }

    def _build_timeline(self):
        return {"generated_at": self._generated_at}
